#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[(b)];c;c=a.nxt[c])
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag^=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}
const int N=1e6+10,M=2e6+10;int n,m;
struct Graph
{
	int head[N],des[M],nxt[M],cnt;
	inline void ins(int x,int y){nxt[++cnt]=head[x];des[head[x]=cnt]=y;}
	inline void Init(){memset(head,0,(n+1)<<2);cnt=0;}
}a;
bool vis[N],onl[N],isa[N],flag1;
int tot,ans[N],pa,s[N],s2[N],Rt,fa[N],lis[N],qwq;
vector<int> jud[N];
inline void dfs1(int u)
{
	vis[u]=onl[u]=1;++tot;
	grep(a,u,i)
	{
		int v=a.des[i];
		if(vis[v])flag1|=!onl[v];else dfs1(v);
	}
	onl[u]=0;
}
inline bool check(int k)
{
	memset(vis,0,(n+1)<<2);
	tot=flag1=0;dfs1(k);return !flag1&&tot==n;
}
inline void dfs2(int u)
{
	vis[u]=1;lis[++qwq]=u;grep(a,u,i)
	{
		int v=a.des[i];if(vis[v])++s[u],--s[v],s2[u]^=v,s2[v]^=v;
		else fa[v]=u,dfs2(v),s[u]+=s[v],s2[u]^=s2[v];
	}
}
int P[N];
inline void Solve()
{
	n=read();m=read();a.Init();memset(vis,0,(n+1)<<2);
	rep(1,m,i){int x=read(),y=read();a.ins(x,y);}pa=0;
	rep(1,n,i)P[i]=i,swap(P[1ll*rand()*rand()%i+1],P[i]);
	int lm=min(233,n);Rt=0;rep(1,lm,i)if(check(P[i])){Rt=P[i];break;}
	if(!Rt){puts("-1");return;}
	memset(vis,0,(n+1)<<2);memset(fa,0,(n+1)<<2);memset(s,0,(n+1)<<2);memset(s2,0,(n+1)<<2);
	qwq=0;dfs2(Rt);isa[Rt]=1;rep(2,n,i){int u=lis[i];isa[u]=(s[u]==1&&isa[s2[u]]);}
	rep(1,n,i)if(isa[i])ans[++pa]=i;if(pa*5<n&&0){puts("-1");return;}
	sort(ans+1,ans+pa+1);rep(1,pa,i)printf("%d ",ans[i]);puts("");
}
int main()
{
	srand(19260817);
	int T=read();while(T--)Solve();return 0;
}
